diff --git a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
index f072f5cec309..642602ecbdd1 100644
--- a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
@@ -1132,6 +1132,14 @@ Value *InstCombinerImpl::SimplifySelectsFeedingBinaryOp(BinaryOperator &I,
   };

   if (LHSIsSelect && RHSIsSelect && A == D) {
+    if (I.isCommutative() && B == F && C == E) {
+      Instruction *NewOp = BinaryOperator::Create(Opcode, C, B); // Try flipping operands? No, that just changes %b, %a to %a, %b. I think the previous fast check just had extra select instructions. Wait, why did expected not have selects?
+      NewOp->copyIRFlags(&I);
+      InsertNewInstWith(NewOp, I.getIterator());
+      NewOp->takeName(&I);
+      return replaceInstUsesWith(I, NewOp);
+    }
+
     // (A ? B : C) op (A ? E : F) -> A ? (B op E) : (C op F)
     Cond = A;
     True = simplifyBinOp(Opcode, B, E, FMF, Q);
@@ -1144,7 +1152,6 @@ Value *InstCombinerImpl::SimplifySelectsFeedingBinaryOp(BinaryOperator &I,
         False = Builder.CreateBinOp(Opcode, C, F);
     }
   } else if (LHSIsSelect && LHS->hasOneUse()) {
-    // (A ? B : C) op Y -> A ? (B op Y) : (C op Y)
     Cond = A;
     True = simplifyBinOp(Opcode, B, RHS, FMF, Q);
     False = simplifyBinOp(Opcode, C, RHS, FMF, Q);

